<?php declare(strict_types=1);
namespace App\Services;
final class StreamingProfileService { public function select(array $media,?string $name=null):array{$config=config('profiles');$name=$name?:$config['default'];$profile=$config['profiles'][$name]??$config['profiles']['auto'];if($name!=='auto')return array_merge(['name'=>$name],$profile);$requiresPerformanceProfile=$media['height']>1080||($media['height']>=1080&&$media['fps']>30);return ['name'=>'auto','resolution'=>$requiresPerformanceProfile?$config['adaptive']['maximum_resolution']:config('stream.default_resolution'),'fps'=>$requiresPerformanceProfile?$config['adaptive']['maximum_fps']:config('ffmpeg.fps'),'preset'=>$requiresPerformanceProfile?$config['adaptive']['high_input_preset']:config('ffmpeg.preset'),'bitrate'=>config('stream.default_bitrate')];} }
